      },
    ],
    `Conserva questo token in modo sicuro: consente l'accesso alla dashboard e alle integrazioni API. Puoi accedere anche dal <a href="${dashboardUrl}" style="color:#ff8c42;font-weight:600;">dashboard Zirèl</a>.`,
    [
      { label: 'Apri dashboard', href: dashboardUrl }
    ]
  );

} else if (template === 'tenant_api_token_regenerated') {
  subject = `Il tuo nuovo token di accesso Zirèl`;
  text = `Ciao,\n\nper il workspace ${businessName} è stato generato un nuovo token di accesso.\n\nNuovo token:\n${payload.api_token || 'N/D'}\n\nImportante: il token precedente non è più valido.\n\nConserva questo token in modo sicuro.\n\nDashboard: ${dashboardUrl}\n\nTeam Zirèl`;
  html = renderShell(
