    `Per il workspace <strong>${businessName}</strong> è stato generato un nuovo token di accesso.`,
    [
      { label: 'Workspace', value: businessName },
      { label: 'Tenant ID', value: payload.tenant_id || 'N/D' },
      {
        label: 'Nuovo token API',
        value: `<div style="background:#f8fafc;border:1px solid #cbd5e1;border-radius:12px;padding:14px 16px;font-family:'Courier New',Courier,monospace;font-size:14px;line-height:1.6;color:#0f172a;word-break:break-all;">${payload.api_token || 'N/D'}</div><div style="margin-top:8px;font-size:12px;color:#64748b;">Puoi copiare il token direttamente da questo riquadro.</div>`
