const formatDate = (value) => {
  if (!value) return 'N/D';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return String(value);
  return date.toLocaleDateString('it-IT', {
    day: 'numeric',
    month: 'long',
    year: 'numeric',
    timeZone: 'Europe/Rome',
  });
};

const pad = (value) => String(value).padStart(2, '0');

const buildLocalDateTime = (dateValue, timeValue) => {
  const dateRaw = String(dateValue || '').trim();
  const timeRaw = String(timeValue || '').trim();
  if (!dateRaw || !timeRaw) return null;

  const [year, month, day] = dateRaw.split('-').map(Number);
  const [hour, minute] = timeRaw.split(':').map(Number);

  if (!year || !month || !day || Number.isNaN(hour) || Number.isNaN(minute)) return null;

  return { year, month, day, hour, minute };
};

const toCalendarStamp = (parts) =>
  parts ? `${parts.year}${pad(parts.month)}${pad(parts.day)}T${pad(parts.hour)}${pad(parts.minute)}00` : '';

const addMinutes = (parts, minutesToAdd) => {
  if (!parts) return null;
  const d = new Date(Date.UTC(parts.year, parts.month - 1, parts.day, parts.hour, parts.minute + minutesToAdd, 0));
  return {
    year: d.getUTCFullYear(),
    month: d.getUTCMonth() + 1,
    day: d.getUTCDate(),
    hour: d.getUTCHours(),
    minute: d.getUTCMinutes(),
  };
};

const toQueryString = (params) =>
  Object.entries(params)
    .filter(([, value]) => value !== undefined && value !== null && value !== '')
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
    .join('&');

const createGoogleCalendarUrl = ({ title, details, location, startDate, startTime, durationMinutes }) => {
  const start = buildLocalDateTime(startDate, startTime);
  if (!start) return '';
  const end = addMinutes(start, durationMinutes);

  const query = toQueryString({
    action: 'TEMPLATE',
    text: title,
    details,
    location,
    ctz: 'Europe/Rome',
    dates: `${toCalendarStamp(start)}/${toCalendarStamp(end)}`,
  });

  return `https://calendar.google.com/calendar/render?${query}`;
};

const createIcsUrl = ({ type, entityId, tenantId }) => {
  const webhookBase = 'https://primary-production-b2af.up.railway.app/webhook/zirel-calendar-ics';
  if (!type || !entityId || !tenantId) return '';

  const query = toQueryString({
    type,
    id: entityId,
    tenant_id: tenantId,
  });

  return `${webhookBase}?${query}`;
};

