    : `Aggiornamento richiesta tavolo\n\nCliente: ${payload.nome_cliente || 'N/D'}\nTelefono: ${payload.telefono || 'N/D'}\nEmail: ${payload.email || 'N/D'}\nStato: ${statusLabel}\nMotivo rifiuto: ${payload.rejection_reason || 'Nessuno'}\nNuova proposta: ${payload.proposed_date || 'N/D'} ${payload.proposed_time ? 'alle ' + payload.proposed_time : ''}\nNota operativa: ${payload.change_note || 'Nessuna'}\nOperatore: ${payload.actor || 'dashboard'}`;
  html = renderShell(
    'Aggiornamento richiesta interna',
    `La richiesta per <strong>${activity}</strong> è stata aggiornata dalla dashboard.`,
    isAppointment
      ? [
          { label: 'Cliente', value: payload.nome || 'N/D' },
          { label: 'Telefono', value: payload.telefono || 'N/D' },
          { label: 'Email', value: payload.email || 'N/D' },
          { label: 'Stato', value: statusLabel },
          { label: 'Motivo rifiuto', value: payload.rejection_reason || 'Nessuno' },
          { label: 'Nuova proposta', value: (payload.proposed_date || 'N/D') + (payload.proposed_time ? ' alle ' + payload.proposed_time : '') },
          { label: 'Nota operativa', value: payload.change_note || 'Nessuna' },
          { label: 'Operatore', value: payload.actor || 'dashboard' },
        ]
      : [
          { label: 'Cliente', value: payload.nome_cliente || 'N/D' },
          { label: 'Telefono', value: payload.telefono || 'N/D' },
          { label: 'Email', value: payload.email || 'N/D' },
          { label: 'Stato', value: statusLabel },
          { label: 'Motivo rifiuto', value: payload.rejection_reason || 'Nessuno' },
          { label: 'Nuova proposta', value: (payload.proposed_date || 'N/D') + (payload.proposed_time ? ' alle ' + payload.proposed_time : '') },
          { label: 'Nota operativa', value: payload.change_note || 'Nessuna' },
          { label: 'Operatore', value: payload.actor || 'dashboard' },
        ],
    'Puoi aprire la dashboard richieste per vedere il dettaglio completo e la timeline aggiornata.'
  );
} else {
  subject = `Nuova richiesta interna • ${activity}`;
  text = `Nuova richiesta appuntamento\n\nAttività: ${activity}\nCliente: ${payload.nome || 'N/D'}\nTelefono: ${payload.telefono || 'N/D'}\nEmail: ${payload.email || 'N/D'}\nData: ${payload.data_appuntamento_label || payload.data_appuntamento || 'N/D'}\nOra: ${payload.orario || 'N/D'}\nMotivo: ${payload.motivo || 'N/D'}\nStato: ${statusLabel}`;

  const internalDashboardUrl = 'https://dashboard.zirel.org?tab=prenotazioni';
  const googleUrl = createGoogleCalendarUrl({
    title: `Appuntamento - ${payload.nome || 'Cliente'}`,
    details: [
      `Attività: ${activity}`,
      `Cliente: ${payload.nome || 'N/D'}`,
      `Telefono: ${payload.telefono || 'N/D'}`,
      `Email: ${payload.email || 'N/D'}`,
      `Motivo: ${payload.motivo || 'N/D'}`,
      `Stato: ${statusLabel}`,
      `Note: ${payload.note || 'Nessuna'}`,
    ].join('\n'),
    location: activity,
    startDate: payload.data_appuntamento,
    startTime: payload.orario,
    durationMinutes: 30,
  });
  const icsUrl = createIcsUrl({
    type: 'appointment',
    entityId: $json.related_entity_id,
    tenantId: $json.tenant_id,
  });

  html = renderShell(
    'Nuova richiesta appuntamento',
    `È stata ricevuta una nuova richiesta da gestire per <strong>${activity}</strong>.`,
    [
      { label: 'Cliente', value: payload.nome || 'N/D' },
      { label: 'Telefono', value: payload.telefono || 'N/D' },
      { label: 'Email', value: payload.email || 'N/D' },
      { label: 'Data', value: payload.data_appuntamento_label || payload.data_appuntamento || 'N/D' },
      { label: 'Ora', value: payload.orario || 'N/D' },
      { label: 'Motivo', value: payload.motivo || 'N/D' },
      { label: 'Stato', value: statusLabel },
      { label: 'Trace', value: payload.trace_id || 'N/D' },
    ],
    'Apri il dashboard o il thread operativo per gestire la richiesta.',
    [
      { label: 'Apri in dashboard', href: internalDashboardUrl },
      ...(googleUrl ? [{ label: 'Aggiungi a Google Calendar', href: googleUrl }] : []),
      ...(icsUrl ? [{ label: 'Scarica .ics', href: icsUrl, variant: 'secondary' }] : []),
    ]
  );
}

return [{
  json: {
    ...$json,
    rendered_email: {
      from: 'Zirèl <noreply@zirel.org>',
      to: recipientEmail ? [recipientEmail] : [],
      subject,
      text,
      html,
    },
  },
}];

const payload = typeof $json.payload === 'string' ? JSON.parse($json.payload) : ($json.payload || {});
const template = String($json.template_key || '').trim();
const relatedType = String($json.related_entity_type || '').trim();
const relatedId = String($json.related_entity_id || '').trim();

const statusLabel = ({
  confirmed: 'Confermata',
  confermata: 'Confermata',
  manual_review: 'Verifica manuale',
  rejected: 'Non disponibile',
  rifiutata: 'Non disponibile',
  annullata: 'Non disponibile',
  pending: 'In lavorazione',
  change_proposed: 'Proposta inviata',
})[String(payload.booking_status || payload.status || payload.availability_status || '').trim().toLowerCase()] || 'In lavorazione';

const phoneRaw = String(payload.telefono || '').trim();
const emailRaw = String(payload.email || '').trim().toLowerCase();

const sourceLabelMap = {
  qr_room: 'QR camera',
  qr_area: 'QR area',
  qr_hotel: 'QR struttura',
  chat_widget: 'Widget sito',
  public_chat: 'Chat pubblica',
};

const sourceLabel = sourceLabelMap[String(payload.source || '').trim()] || String(payload.source || 'Chat').trim() || 'Chat';

const cleanTelegramText = (value) =>
  String(value || '')
    .replace(/[_*[\]()`~>#+=|{}.!]/g, ' ')
    .replace(/&/g, 'e')
    .replace(/</g, ' ')
    .replace(/>/g, ' ')
    .replace(/\s+\n/g, '\n')
    .replace(/\n\s+/g, '\n')
    .replace(/[ \t]{2,}/g, ' ')
    .trim();

let text = 'Nuova richiesta Zirèl';
let telegram_actions_disabled = false;

if (template === 'hotel_reception_request_internal') {
  telegram_actions_disabled = true;
  text = [
    'Nuova richiesta reception',
    '',
    'Struttura: ' + (payload.nome_struttura || 'Hotel'),
    'Camera: ' + (payload.room || 'N/D'),
    'Area: ' + (payload.area || 'N/D'),
    'Ospite: ' + (payload.guest_name || 'N/D'),
    'Telefono: ' + (phoneRaw || 'N/D'),
    'Tipo: ' + (payload.request_type || 'generic_request'),
    'Quando: ' + (payload.requested_time || 'Appena possibile'),
    'Richiesta: ' + (payload.request_text || 'N/D'),
    'Origine: ' + sourceLabel,
    'Trace: ' + (payload.trace_id || 'N/D'),
  ].join('\n');
} else if (template === 'hotel_internal_alert') {
  text = [
    'Nuova richiesta soggiorno',
    '',
    'Struttura: ' + (payload.nome_struttura || 'Hotel'),
    'Cliente: ' + (payload.nome || 'N/D'),
    'Telefono: ' + (phoneRaw || 'N/D'),
    'Email: ' + (emailRaw || 'N/D'),
    '',
    'Soggiorno: ' + (payload.checkin_date || 'N/D') + ' -> ' + (payload.checkout_date || 'N/D'),
    'Ospiti: ' + String(payload.ospiti_totali || 'N/D'),
    'Camera: ' + (payload.room_type_requested || 'Da definire'),
    'Servizi: ' + (payload.servizi_richiesti || 'Nessuno'),
    'Note: ' + (payload.note_prenotazione || 'Nessuna'),
    '',
    'Stato: ' + statusLabel,
  ].join('\n');
} else if (template === 'restaurant_internal_alert') {
  text = [
    'Nuova richiesta tavolo',
    '',
    'Cliente: ' + (payload.nome_cliente || 'N/D'),
    'Telefono: ' + (phoneRaw || 'N/D'),
    ...(emailRaw ? ['Email: ' + emailRaw] : []),
    'Data: ' + (payload.data_prenotazione_label || payload.data_prenotazione || 'N/D'),
    'Ora: ' + (payload.ora || 'N/D'),
    'Persone: ' + String(payload.persone || 'N/D'),
    'Note: ' + (payload.note_prenotazione || 'Nessuna'),
    '',
    'Stato: ' + statusLabel,
  ].join('\n');
} else {
  text = [
    'Nuova richiesta appuntamento',
    '',
    'Cliente: ' + (payload.nome || 'N/D'),
    'Telefono: ' + (phoneRaw || 'N/D'),
    'Email: ' + (emailRaw || 'N/D'),
    'Data: ' + (payload.data_appuntamento_label || payload.data_appuntamento || 'N/D'),
    'Ora: ' + (payload.orario || 'N/D'),
    'Motivo: ' + (payload.motivo || 'N/D'),
    '',
    'Stato: ' + statusLabel,
  ].join('\n');
}

const callbackSuffix = relatedType && relatedId
  ? [relatedType, relatedId].join('|')
  : '';

return [{
  json: {
    ...$json,
    rendered_telegram_text: cleanTelegramText(text),
    telegram_actions_disabled,
    telegram_accept_callback_data: telegram_actions_disabled ? '' : (callbackSuffix ? `accept|${callbackSuffix}` : ''),
    telegram_reject_callback_data: telegram_actions_disabled ? '' : (callbackSuffix ? `reject|${callbackSuffix}` : ''),
  },
}];

const now = Date.now();
return items.filter((item) => {
  const nextRetry = item.json.next_retry_at;
  if (!nextRetry) return true;
  const ts = new Date(nextRetry).getTime();
  return !Number.isNaN(ts) && ts <= now;
});

const sources = $('If Email Channel?1').all();
return items.map((item, index) => {
  const src = sources[index]?.json || {};
  return { json: { id: src.id, status: 'sent', sent_at: new Date().toISOString(), last_error: null } };
});

const sources = $('If Email Channel?1').all();
return items.map((item, index) => {
  const src = sources[index]?.json || {};
  const retry = Number(src.retry_count || 0) + 1;
  const max = Number(src.max_retries || 5);
  const failed = retry >= max;
  const backoffMin = Math.min(60, Math.pow(2, retry));
  return { json: { id: src.id, status: failed ? 'failed' : 'pending', retry_count: retry, next_retry_at: new Date(Date.now() + backoffMin * 60 * 1000).toISOString(), last_error: 'EMAIL_SEND_FAILED' } };
});

const sources = $('If Telegram Channel?1').all();

return items
  .map((item, index) => {
    const src = sources[index]?.json || {};
    const id = src.id || item.json.id || '';
    if (!id) return null;

    return {
      json: {
        id,
        status: 'sent',
        sent_at: new Date().toISOString(),
        last_error: null
      }
    };
  })
  .filter(Boolean);

const sources = $('If Telegram Channel?1').all();

return items
  .map((item, index) => {
    const src = sources[index]?.json || {};
    const id = src.id || item.json.id || '';
    if (!id) return null;

    const retry = Number(src.retry_count || 0) + 1;
    const max = Number(src.max_retries || 5);
    const failed = retry >= max;
    const backoffMin = Math.min(60, Math.pow(2, retry));

    return {
      json: {
        id,
        status: failed ? 'failed' : 'pending',
        retry_count: retry,
        next_retry_at: new Date(Date.now() + backoffMin * 60 * 1000).toISOString(),
        last_error: 'TELEGRAM_SEND_FAILED'
      }
    };
  })
  .filter(Boolean);
